@scottmcm:

```
fn foo(_1: &dyn Sub) -> &dyn Sup {
    debug x => _1;
    let mut _0: &dyn Sup;

    bb0: {
        _0 = copy _1 as &dyn Sup (PointerCoercion(Unsize, Implicit));
